import React, { useState } from 'react';

const Contact = ({ content = {} }) => {
  const {
    title = 'Contactez-nous',
    subtitle = 'Nos experts sont disponibles pour vous répondre',
    buttonText = 'Envoyer',
    successMessage = 'Message envoyé avec succès!'
  } = content;

  const [formData, setFormData] = useState({
    name: '',
    email: '',
    phone: '',
    message: ''
  });

  const handleChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value
    });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    alert(successMessage);
    setFormData({ name: '', email: '', phone: '', message: '' });
  };

  return (
    <section className="py-20 bg-surface" id="contact">
      <div className="container mx-auto px-4">
        <div className="max-w-4xl mx-auto">
          <div className="text-center mb-12">
            <div className="w-16 h-16 bg-gradient-to-r from-yellow-400 to-yellow-500 rounded-2xl mx-auto mb-4 flex items-center justify-center">
              <i className="fas fa-envelope text-2xl text-dark"></i>
            </div>
            <h2 className="text-4xl font-bold text-gradient mb-4">{title}</h2>
            <p className="text-xl text-gray-600">{subtitle}</p>
          </div>

          <div className="bg-surface rounded-3xl p-8 md:p-12 shadow-2xl border border-gray-100">
            <form className="contact-form space-y-6" onSubmit={handleSubmit}>
              <div className="grid md:grid-cols-2 gap-6">
                <div className="form-group">
                  <label className="block text-sm font-semibold text-gray-700 mb-2">Votre nom</label>
                  <input 
                    type="text" 
                    name="name" 
                    value={formData.name}
                    onChange={handleChange}
                    placeholder="Votre nom" 
                    className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:border-yellow-400 focus:ring-2 focus:ring-yellow-400/20 outline-none transition-all"
                    required 
                  />
                </div>
                <div className="form-group">
                  <label className="block text-sm font-semibold text-gray-700 mb-2">Votre email</label>
                  <input 
                    type="email" 
                    name="email" 
                    value={formData.email}
                    onChange={handleChange}
                    placeholder="Votre email" 
                    className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:border-yellow-400 focus:ring-2 focus:ring-yellow-400/20 outline-none transition-all"
                    required 
                  />
                </div>
              </div>
              <div className="form-group">
                <label className="block text-sm font-semibold text-gray-700 mb-2">Votre téléphone</label>
                <input 
                  type="tel" 
                  name="phone" 
                  value={formData.phone}
                  onChange={handleChange}
                  placeholder="Votre téléphone" 
                  className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:border-yellow-400 focus:ring-2 focus:ring-yellow-400/20 outline-none transition-all"
                  required 
                />
              </div>
              <div className="form-group">
                <label className="block text-sm font-semibold text-gray-700 mb-2">Votre message</label>
                <textarea 
                  name="message" 
                  value={formData.message}
                  onChange={handleChange}
                  placeholder="Votre message" 
                  rows="5" 
                  className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:border-yellow-400 focus:ring-2 focus:ring-yellow-400/20 outline-none transition-all"
                  required
                ></textarea>
              </div>
              <button 
                type="submit"
                className="w-full bg-gradient-to-r from-yellow-400 to-yellow-500 text-dark font-bold py-4 px-10 rounded-2xl hover:from-yellow-500 hover:to-yellow-600 transition-all transform hover:scale-105 shadow-2xl"
              >
                <i className="fas fa-paper-plane mr-2"></i>
                {buttonText}
              </button>
            </form>
          </div>
        </div>
      </div>
    </section>
  );
};

export default Contact;
